$test('operational error redaction',function()use($yes,$eq){$cases=['buyer@example.com'=>'buyer@example.com','sk_test_abcdefghijklmnopqrstuvwxyz'=>'sk_test_abcdefghijklmnopqrstuvwxyz','whsec_abcdefghijklmnopqrstuvwxyz'=>'whsec_abcdefghijklmnopqrstuvwxyz','pi_123456789'=>'pi_123456789','cus_123456789'=>'cus_123456789','evt_123456789'=>'evt_123456789','Bearer abc.def.ghi'=>'abc.def.ghi','Basic dXNlcjpwYXNz'=>'dXNlcjpwYXNz','API-Key: api-hyphen-secret'=>'api-hyphen-secret','API Key=api-space-secret'=>'api-space-secret','X-API-Key: api-header-secret'=>'api-header-secret','x_api_key=api-underscore-secret'=>'api-underscore-secret','Stripe-Signature: t=12345,v1=signature-secret'=>'signature-secret','https://dbuser:dbpassword@example.test/private'=>'dbpassword','password=hunter2'=>'hunter2','token=secret-value'=>'secret-value','api_key=api-secret'=>'api-secret','mysql:host=db;dbname=marketplace;password=hunter2'=>'dbname=marketplace','https://example.test/path?token=secret#private'=>'token=secret',str_repeat('a',32).'.'.str_repeat('b',64)=>str_repeat('b',64),'<b>HTML</b>'=>'<b>',"line one\r\n\x00line two\nStack trace:\n#0 /private/file.php(1): secret"=>'#0 /private'];foreach($cases as $input=>$needle){$individual=OperationalErrorSanitizer::sanitize($input,200);$yes($individual!==''&&!str_contains($individual,$needle)&&!preg_match('/[\r\n\x00-\x1F\x7F]/',$individual));}$combined=implode(' | ',array_keys($cases));$safe=OperationalErrorSanitizer::sanitize($combined,800);foreach(array_values($cases) as $value)$yes(!str_contains($safe,$value));$yes($safe!==''&&mb_strlen($safe)<=800&&!preg_match('/[\r\n\x00-\x1F\x7F]/',$safe));$only=OperationalErrorSanitizer::sanitize('token=secret-value',100);$yes($only!==''&&mb_strlen($only)<=100);$eq(OperationalErrorSanitizer::context("Bad Context\nTOKEN"),'bad_context_token');});
$test('idempotent and recoverable log append',function()use($eq,$yes){$path=tempnam(sys_get_temp_dir(),'asset-moth-mail-');$entry=['timestamp'=>'2026-07-20T00:00:00Z','message_id'=>77,'template'=>'campaign','recipient_hash'=>str_repeat('a',64),'subject'=>'Safe subject','body_bytes'=>10];$yes(EmailQueueService::appendLogOnce($path,$entry));$eq(EmailQueueService::appendLogOnce($path,$entry),false);file_put_contents($path,'{"message_id":999',FILE_APPEND);$second=$entry;$second['message_id']=78;$yes(EmailQueueService::appendLogOnce($path,$second));$lines=file($path,FILE_IGNORE_NEW_LINES|FILE_SKIP_EMPTY_LINES);$eq(count($lines),2);$ids=[];foreach($lines as $line){$decoded=json_decode($line,true);$yes(is_array($decoded));$ids[]=$decoded['message_id'];$yes(!isset($decoded['recipient_email'],$decoded['template_data'],$decoded['body'],$decoded['unsubscribe_url']));}$eq($ids,[77,78]);$threw=false;try{EmailQueueService::appendLogOnce($path,['message_id'=>0]);}catch(InvalidArgumentException $e){$threw=true;}$yes($threw);file_put_contents($path,"{bad json}\n",FILE_APPEND);$threw=false;try{EmailQueueService::appendLogOnce($path,array_merge($entry,['message_id'=>79]));}catch(RuntimeException $e){$threw=true;}$yes($threw);unlink($path);});
